     1→import { ApiClient } from "./client";
     2→import type { ApiNamespace } from "./types";
     3→
     4→// Cache for storing created API clients
     5→const clientCache = new Map<string, ApiClient>();
     6→
     7→// Generate a cache key for the given parameters
     8→const getCacheKey = (performRedirect: boolean, namespace: string): string => {
     9→  return `${namespace}-${performRedirect}`;
    10→};
    11→
    12→export const getApiClient = (
    13→  performRedirect = true,
    14→  namespace: ApiNamespace = "org",
    15→): ApiClient => {
    16→  const cacheKey = getCacheKey(performRedirect, namespace);
    17→
    18→  // Check if we already have a client for this configuration
    19→  const cachedClient = clientCache.get(cacheKey);
    20→  if (cachedClient) {
    21→    return cachedClient;
    22→  }
    23→
    24→  // Create a new client for this configuration
    25→  const newClient = new ApiClient({
    26→    namespace,
    27→    performRedirect,
    28→  });
    29→
    30→  // Store it in the cache for future use
    31→  clientCache.set(cacheKey, newClient);
    32→
    33→  return newClient;
    34→};
