      const parts: string[] = [];

      if (status) {
        parts.push(`HTTP ${status}`);
        if (statusText) {
          parts.push(statusText);
        }
      }

      if (code && code !== "ERR_BAD_REQUEST" && code !== "ERR_BAD_RESPONSE") {
        parts.push(`(${code})`);
      }

      if (
        axiosMessage &&
        axiosMessage !== `Request failed with status code ${status}`
      ) {
        parts.push(axiosMessage);
      }

      errorMessage =
        parts.length > 0 ? parts.join(" - ") : "An axios error has occurred.";
    }

    return new ApiError(
      errorMessage,
      ApiClientErrorTypes.Axios,
      error.response,
    );
